use std::env;

pub fn get_database_connection() -> Result<tokio_postgres::Client, tokio_postgres::Error> {
    let database_url = env::var("DATABASE_URL")
        .expect("DATABASE_URL must be set in environment variables");
    
    let (client, connection) = tokio_postgres::connect(&database_url, tokio_postgres::NoTls).await?;
    
    tokio::spawn(async move {
        if let Err(e) = connection.await {
            eprintln!("Database connection error: {}", e);
        }
    });
    
    Ok(client)
}

pub async fn establish_connection() -> tokio_postgres::Client {
    get_database_connection()
        .await
        .expect("Failed to connect to database. Ensure DATABASE_URL environment variable is set correctly.")
}